INSERT INTO product (sku, name, description, category, price, cost, stock_quantity, manufacturer, supplier, weight, dimensions, is_active, created_at, updated_at) VALUES
('PEN-BLK-001', 'Sphinx-Approved Scribe Pen', 'FantaCo Happiness Herders certified ballpoint: ergonomic grip for iambic margin notes, Sonnet Mode brainstorms, and HR Sphinx deciphering. Smooth black ink. Glitter belongs in the Benevolent Overlord Council wish program, not the ink cartridge.', 'Writing Supplies', 2.99, 1.25, 500, 'OfficePro', 'Global Office Supplies', 0.05, '5.5x0.4x0.4', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('PAPER-A4-100', 'Chronicle of Possibility A4 Ream', 'Bright white 80gsm paper for BOC-worthy proposals, speakeasy menus, and adventure-allotment itineraries. 100 sheets per pack. Suitable for Enchanted Forest memos, interstellar redlines, and Zen Garden OKRs. Printer jam resilience sold separately.', 'Paper Products', 4.99, 2.50, 200, 'PaperCo', 'Paper Wholesale Inc', 0.50, '29.7x21x0.5', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('STAPLER-001', 'BOC Wish-Ready Heavy Stapler', '20-sheet stapler tuned for Friday-before-long-weekend document storms. Tiny optional glitter reservoir for employees whose wishes were granted (food-safe glitter only; HR prohibits unauthorized alchemy on rival staplers). Chrome trim nods to 1920s Speakeasy pods.', 'Desk Accessories', 12.99, 6.50, 150, 'OfficePro', 'Global Office Supplies', 0.30, '15x5x3', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('NOTEBOOK-A5-001', 'Adventure Allotment Field Journal', 'A5 spiral notebook, 100 lined pages, forest-green wire. Inside cover prints one Squirrel phrase and three Dolphin phrases for interdepartmental harmony during acorn season and high tide. Capture sabbatical ideas and Atlantean action items.', 'Notebooks', 5.99, 2.75, 300, 'PaperCo', 'Paper Wholesale Inc', 0.20, '21x14.8x1', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('SCISSORS-001', 'Ribbon & Cape Trimming Shears', 'Eight-inch stainless shears with comfortable handles for Interpretive Dance Off costumes, flash-mob tailoring, and ordinary tape. Capybara jazz band not included. Please do not use near the office griffin; he is on a strict glitter-and-pickle diet.', 'Desk Accessories', 8.99, 4.25, 100, 'OfficePro', 'Global Office Supplies', 0.15, '20x8x1', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('MARKER-BLK-001', 'Void-Signing Permanent Marker', 'Fine-point black permanent ink for mood-board prophecies, speakeasy chalkboard passwords, and labeling artisan soda experiments. Cap retention tested under mild zero-gravity brainstorming conditions (floating stapler warnings apply).', 'Writing Supplies', 1.99, 0.75, 400, 'OfficePro', 'Global Office Supplies', 0.03, '14x1x1', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('TAPE-DISP-001', 'Portal-Sealing Desktop Tape Dispenser', 'Weighted base keeps tape earthbound during optional zero-gravity brainstorms. Ships with crystal-clear office tape. Ideal for sealing snack-bar inventory lists, holographic projector borders, and pool-noodle jousting brackets.', 'Desk Accessories', 6.99, 3.25, 200, 'OfficePro', 'Global Office Supplies', 0.20, '12x6x3', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('HLGHT-YEL-001', 'Highlighter of Destiny (Yellow)', 'Fluorescent chisel tip for marking lavender-field calm versus mosh-pit urgency on any priority list. Compatible with whale-song notetaking and Silent Disco For One kanban boards. Chisel edge nicknamed the pool-noodle lane for executive summaries.', 'Writing Supplies', 1.49, 0.60, 600, 'OfficePro', 'Global Office Supplies', 0.02, '14x1x1', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('DESK-ORG-001', 'Imagination Pod Triage Vault', 'Three-compartment black organizer for urgent scrolls, whimsical detritus, and items awaiting wise-owl review. Includes sticker sheet with playful labels. Pairs with self-stocking snack bars and mood projectors in certified Gilded Cage pods.', 'Desk Accessories', 19.99, 10.00, 75, 'OfficePro', 'Global Office Supplies', 0.50, '25x15x10', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('POSTIT-001', 'Flash Mob & Compliment Sticky Notes', '3x3 inch pads, 100 sheets per pad, pastel stack. Some sheets ship with tiny printed affirmations in the spirit of the Champagne Compliments Catharsis Chamber. Jazz hands optional; personalized theme song sold separately.', 'Paper Products', 3.99, 1.75, 250, 'PaperCo', 'Paper Wholesale Inc', 0.10, '7.6x7.6x0.5', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('DESK-ELEC-001', 'Imagination Pod Electric Standing Desk', 'Premium electric desk with memory presets mapped to Forest, Speakeasy, Zen, and Launchpad workflows. Height 28-48 inches, 60x30 inch surface, matte black finish. Optional accessory rail welcomes magnetic desk toys and cable ascension rituals.', 'Office Furniture', 599.99, 350.00, 25, 'ErgoWorks', 'Office Furniture Solutions', 85.00, '152x76x122', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('CHAIR-BAS-001', 'Synchronized Swivel Training Chair', 'ErgoWorks entry throne for daily work and competitive office chair ballet. Adjustable height, padded seat and back, stable base for graceful spins. Pool-noodle jousting certification not included. Thermostat-week privileges remain tournament-gated.', 'Office Furniture', 89.99, 45.00, 100, 'ErgoWorks', 'Office Furniture Solutions', 12.00, '60x60x120', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('CHAIR-PRM-001', 'Executive Chair (Scepter-Compatible Comfort)', 'High-end ergonomic chair: lumbar support, adjustable armrests, headrest, memory foam. Griffin-feather-comforter levels of comfort marketed metaphorically only. Magnetic pillow option syncs with gaming line; Scepter of Supreme Snacking Authority not included.', 'Office Furniture', 299.99, 175.00, 50, 'ErgoWorks', 'Office Furniture Solutions', 18.00, '65x65x130', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('MAT-FLOOR-001', 'Jousting-Lane Polycarbonate Chair Mat', 'Heavy-duty carpet mat with anti-slip backing for spirited swivel footwork and post-tournament cooldowns. Subtle durability for dragon-commute grit and unicycle-adjacent office traffic. Polycarbonate clarity: not actual holographic lavender fields.', 'Office Furniture', 49.99, 25.00, 75, 'ErgoWorks', 'Office Furniture Solutions', 3.50, '152x122x0.2', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
